Here's an example C++ function that takes a reference to a std::string containing markdown formatted text and returns a std::string containing HTML formatted text:

```cpp
#include <string>
#include <vector>
#include <algorithm>

std::string markdownToHtml(std::string const& markdown)
{
    std::vector<std::pair<std::string, std::string>> replacements;
    replacements.push_back(std::make_pair("**", "**"));  // bold
    replacements.push_back(std::make_pair("*", "*/"));   // italic
    replacements.push_back(std::make_pair("_", "\_"));   // underscore
    replacements.push_back(std::make_pair("[", "\["));   // square bracket
    replacements.push_back(std::make_pair("]", "\]"));   // closing square bracket
    replacements.push_back(std::make_pair("(`", "(`"));   // left parenthesis
    replacements.push_back(std::make_pair("`", "`"));   // right parenthesis
    replacements.push_back(std::make_pair("[x", "[x"));   // link
    replacements.push_back(std::make_pair("]x", "]x"));   // close link
    replacements.push_back(std::make_pair("-", "-");     // hyphen
    replacements.push_back(std::make_pair("_d", "\_d"));  // date
    replacements.push_back(std::make_pair("_m", "\_m"));  // month
    replacements.push_back(std::make_pair("_y", "\_y");   // year
    std::string html = markdown;
    for (auto& replacement : replacements)
    {
        html = std::regex_replace(html, std::regex("\\b" + replacement.first + "\\b"), replacement.second);
    }
    return html;
}
```

This function takes a reference to a std::string containing markdown formatted text and returns a std::string containing HTML formatted text. It uses a std::vector of std::pair<std::string, std::string> to map markdown tokens to HTML entities. It then loops through the vector and uses std::regex_replace to replace the markdown tokens with their corresponding HTML entities.

Note that this function assumes that the input string only contains markdown syntax. If the input string contains other types of tokens, these will not be converted to HTML entities and may display incorrectly in the final HTML output.

